from itertools import permutations
class Solution:
    def smallestNumber(self, pattern):
        n = len(pattern)
        for perm in permutations('123456789', n + 1):
            ok = True
            for i, ch in enumerate(pattern):
                if ch == 'I' and not perm[i] < perm[i + 1]:
                    ok = False
                    break
                if ch == 'D' and not perm[i] > perm[i + 1]:
                    ok = False
                    break
            if ok:
                return ''.join(perm)
        return ''

