var smallestNumber = function(pattern) {
    const res = [];
    const stack = [];
    for (let i = 0; i <= pattern.length; i++) {
        stack.push(String(i + 1));
        if (i === pattern.length || pattern[i] === 'I') {
            while (stack.length) res.push(stack.pop());
        }
    }
    return res.join('');
};
